"use client";
import { Button } from "@/components/ui/button";
import { motion } from "framer-motion";

const cards = [
  {
    title: "Mountain View",
    copy: "Check out all of these gorgeous mountain trips with beautiful views of, you guessed it, the mountains",
    button: "View Trips",
    img: "https://images.unsplash.com/photo-1501785888041-af3ef285b470?w=800&q=80&auto=format&fit=crop",
  },
  {
    title: "To The Beach",
    copy: "Plan your next beach trip with these fabulous destinations",
    button: "View Trips",
    img: "https://images.unsplash.com/photo-1507525428034-b723cf961d3e?w=800&q=80&auto=format&fit=crop",
  },
  {
    title: "Desert Destinations",
    copy: "It's the desert you've always dreamed of",
    button: "Book Now",
    img: "https://images.unsplash.com/photo-1501785888041-af3ef285b470?w=800&q=80&auto=format&fit=crop",
  },
  {
    title: "Explore The Galaxy",
    copy: "Seriously, straight up, just blast off into outer space today",
    button: "Book Now",
    img: "https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=800&q=80&auto=format&fit=crop",
  },
];

export default function CardLiftMotion() {
  return (
    <main className="page-content grid gap-4 p-4 max-w-6xl mx-auto font-sans sm:grid-cols-2 lg:grid-cols-4">
      {cards.map((card, i) => (
        <motion.div
          key={i}
          className="relative flex items-end overflow-hidden rounded-lg shadow-lg h-[350px] group cursor-pointer"
          whileHover="hover"
          initial="rest"
          animate="rest"
        >
          {/* Background image */}
          <motion.div
            className="absolute inset-0 bg-cover bg-center"
            style={{ backgroundImage: `url(${card.img})` }}
            variants={{
              rest: { scale: 1 },
              hover: { scale: 1.05 },
            }}
            transition={{ duration: 0.6, ease: "easeOut" }}
          />

          {/* Gradient overlay */}
          <div className="absolute inset-0 bg-gradient-to-b from-transparent via-black/40 to-black/70 opacity-90" />

          {/* Content */}
          <motion.div
            className="relative flex flex-col items-center text-center text-white p-4 w-full"
            variants={{
              rest: { y: "60%", transition: { duration: 0.4, ease: "easeOut" } },
              hover: { y: "0%", transition: { duration: 0.4, ease: "easeOut" } },
            }}
          >

            <h3 className="text-lg font-bold mb-4 add-font-family">{card.title}</h3>
            <motion.p
              className="mt-3 text-sm italic opacity-0 group-hover:opacity-100 text-white"
              variants={{
                rest: { opacity: 0, y: 20 },
                hover: { opacity: 1, y: 0 },
              }}
              transition={{ duration: 0.3, delay: 0.1 }}
            >
              {card.copy}
            </motion.p>
            <Button asChild >
            <motion.button
              className="mt-4 "
              variants={{
                rest: { opacity: 0, y: 20 },
                hover: { opacity: 1, y: 0 },
              }}
              transition={{ duration: 0.3, delay: 0.2 }}
            >
              <h3 className="text-sm font-medium add-font-family">{card.button}</h3>
            </motion.button>
            </Button>
          </motion.div>
        </motion.div>
      ))}
    </main>
  );
}
